changeSet.sql:
DO $$
BEGIN
    -- Try to drop the old constraint name (if it exists from migration)
    IF EXISTS (
        SELECT 1 FROM pg_constraint
        WHERE conname = 'annotation_sentence_id_user_id_key'
        AND conrelid = 'annotation'::regclass
    ) THEN
        ALTER TABLE annotation DROP CONSTRAINT annotation_sentence_id_user_id_key;
    END IF;

    -- Try to drop the new constraint name (if it exists from fresh install)
    IF EXISTS (
        SELECT 1 FROM pg_constraint
        WHERE conname = 'uq_annotation_sentence_user'
        AND conrelid = 'annotation'::regclass
    ) THEN
        ALTER TABLE annotation DROP CONSTRAINT uq_annotation_sentence_user;
    END IF;
END $$;

CREATE UNIQUE INDEX IF NOT EXISTS uq_annotation_sentence_user_active
ON annotation (sentence_id, user_id)
WHERE deleted_at IS NULL;
